noncompliant:
#define CUBE(X) ((X) * (X) * (X))  // Noncompliant
void func(void) {
  int i = 2;
  int a = CUBE(++i);  // Dangerous: multiple evaluation of ++i
}

compliant:
inline int cube(int x) {
  return x * x * x;  // Compliant: function instead of macro
}
void func(void) {
  int i = 2;
  int a = cube(++i);  // Safe: i incremented only once
}

int max(int a, int b) {
  return (a > b) ? a : b;  // Compliant: function with proper parameter evaluation
}
